import os
import pty
import select
import signal
import threading
import time
from typing import Optional

from base_terminal import BaseTerminal


class HeadlessTerminal(BaseTerminal):
    """A PTY-backed interactive terminal session.

    The terminal starts an interactive bash shell (`bash -i`) so normal startup
    files such as `~/.bashrc` are sourced. Keystrokes are written directly to the
    pseudo-terminal, which supports interactive programs and modifier keys (for
    example, `"\x03"` for Ctrl-C).
    """

    def __init__(
        self,
        shell: str = "bash",
        startup_wait_sec: float = 0.1,
        encoding: str = "utf-8",
    ) -> None:
        self._shell = shell
        self._encoding = encoding
        self._closed = False
        self._output_parts = []
        self._output_lock = threading.Lock()
        self._reader_stop = threading.Event()

        pid, master_fd = pty.fork()
        if pid == 0:
            # Child process: replace with an interactive shell.
            os.execvp(shell, [shell, "-i"])

        self._pid = pid
        self._master_fd = master_fd

        self._reader_thread = threading.Thread(target=self._reader_loop, daemon=True)
        self._reader_thread.start()

        if startup_wait_sec > 0:
            time.sleep(startup_wait_sec)

    def send_keystrokes(self, keystrokes: str, wait_sec: float = 0.0) -> None:
        if self._closed:
            raise RuntimeError("Terminal is closed")

        os.write(self._master_fd, keystrokes.encode(self._encoding))

        if wait_sec > 0:
            time.sleep(wait_sec)

    def get_output(self, clear: bool = False) -> str:
        with self._output_lock:
            data = "".join(self._output_parts)
            if clear:
                self._output_parts.clear()
        return data

    def clear_output(self) -> None:
        with self._output_lock:
            self._output_parts.clear()

    def is_alive(self) -> bool:
        if self._closed:
            return False

        try:
            pid, _status = os.waitpid(self._pid, os.WNOHANG)
            return pid == 0
        except ChildProcessError:
            return False

    def close(self, terminate_wait_sec: float = 0.2) -> None:
        if self._closed:
            return

        self._closed = True
        self._reader_stop.set()

        # Try graceful termination first.
        if self.is_alive():
            try:
                os.kill(self._pid, signal.SIGHUP)
            except ProcessLookupError:
                pass

            end_time = time.time() + max(terminate_wait_sec, 0.0)
            while time.time() < end_time and self.is_alive():
                time.sleep(0.01)

        # Force-kill if still alive.
        if self.is_alive():
            try:
                os.kill(self._pid, signal.SIGKILL)
            except ProcessLookupError:
                pass

        try:
            os.close(self._master_fd)
        except OSError:
            pass

        if self._reader_thread.is_alive():
            self._reader_thread.join(timeout=0.2)

        # Reap the child if needed.
        try:
            os.waitpid(self._pid, os.WNOHANG)
        except ChildProcessError:
            pass

    def __enter__(self) -> "HeadlessTerminal":
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        self.close()

    def __del__(self) -> None:
        try:
            self.close()
        except Exception:
            # Suppress destructor-time cleanup errors.
            pass

    def _reader_loop(self) -> None:
        while not self._reader_stop.is_set():
            if self._closed:
                return

            ready, _, _ = select.select([self._master_fd], [], [], 0.1)
            if not ready:
                continue

            try:
                chunk = os.read(self._master_fd, 65536)
            except OSError:
                return

            if not chunk:
                return

            text = chunk.decode(self._encoding, errors="replace")
            with self._output_lock:
                self._output_parts.append(text)
